sub constant_time_compare {
    my ($a, $b) = @_;
    return 0 if length($a) != length($b);
    my $result = 0;
    for my $i (0 .. length($a) - 1) {
        $result |= ord(substr($a, $i, 1)) ^ ord(substr($b, $i, 1));
    }
    return $result == 0;
}

